
.status-panel {
  width: 100%;
  max-width: 720px;
  background: var(--c-surface);
  border: 1px solid var(--c-border);
  border-radius: 12px;
  overflow: hidden;
  font-family: var(--font-display);
  font-size: 13px;
  color: var(--c-text);
  line-height: 1.5;
  box-shadow: 0 2px 16px rgba(0, 0, 0, 0.4);
  margin: 0 auto;
}

.content-area {
  padding: 10px 14px;
  min-height: 40px;
}

.empty-hint {
  color: var(--c-text-dim);
  text-align: center;
  padding: 20px;
  font-size: 12px;
}
