
.character-panel {
  display: flex;
  flex-direction: column;
  gap: 10px;
}

.char-basics {
  display: flex;
  gap: 16px;
  flex-wrap: wrap;
}

.basic-item {
  display: flex;
  align-items: baseline;
  gap: 6px;
}

.basic-label {
  font-size: 11px;
  color: var(--c-text-dim);
}

.basic-value {
  font-size: 12px;
  color: var(--c-text-bright);
  font-weight: 500;
}

.basic-value.gold {
  color: var(--c-primary);
}

/* Extra info (伊莎贝ラ magazine) */
.extra-info {
  display: flex;
  gap: 16px;
  flex-wrap: wrap;
  padding: 6px 10px;
  background: rgba(212, 160, 80, 0.06);
  border-radius: 6px;
  border: 1px solid rgba(212, 160, 80, 0.12);
}

.extra-item {
  display: flex;
  align-items: baseline;
  gap: 6px;
}

.extra-label {
  font-size: 11px;
  color: var(--c-text-dim);
}

.extra-value {
  font-size: 12px;
  color: var(--c-text-bright);
}

.extra-value.gold {
  color: var(--c-primary);
}

/* Status bars */
.bars-section {
  display: flex;
  flex-direction: column;
  gap: 6px;
}

.bar-row {
  display: flex;
  align-items: center;
  gap: 8px;
}

.residue-row {
  display: flex;
  align-items: center;
  gap: 8px;
}

.bar-label {
  font-size: 11px;
  color: var(--c-text-dim);
  min-width: 56px;
  flex-shrink: 0;
}

.bar-track {
  flex: 1;
  height: 8px;
  background: var(--c-bar-bg);
  border-radius: 4px;
  overflow: hidden;
}

.bar-fill {
  height: 100%;
  border-radius: 4px;
  transition: width 0.5s ease, background 0.5s ease;
  min-width: 0;
}

.bar-num {
  font-size: 12px;
  font-weight: 600;
  min-width: 28px;
  text-align: right;
  font-variant-numeric: tabular-nums;
}

.residue-value {
  font-size: 12px;
  color: var(--c-text-bright);
}

/* Exp grid */
.section-subhead {
  font-size: 11px;
  font-weight: 600;
  color: var(--c-primary-dim);
  text-transform: uppercase;
  letter-spacing: 0.06em;
  border-bottom: 1px solid var(--c-border);
  padding-bottom: 2px;
}

.exp-grid {
  display: grid;
  grid-template-columns: repeat(4, 1fr);
  gap: 4px 8px;
}

.exp-item {
  display: flex;
  justify-content: space-between;
  align-items: center;
  padding: 2px 6px;
  background: var(--c-card);
  border-radius: 4px;
}

.exp-label {
  font-size: 11px;
  color: var(--c-text-dim);
}

.exp-count {
  font-size: 12px;
  color: var(--c-stat-number);
  font-weight: 600;
  font-variant-numeric: tabular-nums;
}

.detail-text {
  font-size: 11px;
  color: var(--c-text-dim);
  line-height: 1.6;
  word-break: break-all;
}
